def _raw_sensor_tuple(cycle):
    return tuple(getattr(cycle, field) for field in _RAW_SENSOR_FIELDS)


def _live_ingest_key(run_id, sample_ts):
    ts = sample_ts
    if ts.tzinfo is None:
        ts = ts.replace(tzinfo=timezone.utc)
    else:
        ts = ts.astimezone(timezone.utc)
    return f"live|{run_id}|{ts.isoformat()}"


def _delete_duplicate_live_timestamps(PipelineCycle):
    """Delete only safe duplicate live timestamps.

    Kalman posterior rows are stateful. If a duplicate timestamp sits before
    later cycles, deleting it would leave those later rows computed from a
    history that no longer exists. Therefore this only auto-deletes identical
    raw payload duplicates when the duplicate group reaches the run tail.
    """
    duplicate_groups = (
        PipelineCycle.objects.values("run_id", "sample_ts")
        .annotate(n=Count("id"))
        .filter(n__gt=1)
    )
    for group in duplicate_groups.iterator():
        rows = list(
            PipelineCycle.objects.filter(
                run_id=group["run_id"],
                sample_ts=group["sample_ts"],
            ).order_by("cycle_index", "id")
        )
        if len(rows) < 2:
            continue
        ids = [row.id for row in rows]
        max_idx_in_group = max(row.cycle_index for row in rows)
        run_max_idx = (
            PipelineCycle.objects.filter(run_id=group["run_id"])
            .aggregate(m=Max("cycle_index"))
            .get("m")
        )
        if run_max_idx is None:
            run_max_idx = max_idx_in_group

        ref_payload = _raw_sensor_tuple(rows[0])
        same_payload = all(_raw_sensor_tuple(row) == ref_payload for row in rows[1:])
        if not same_payload:
            raise ValueError(
                "estimation migration 0006: duplicate live (run_id, sample_ts) "
                "with conflicting raw sensor payloads. "
                f"run_id={group['run_id']}, sample_ts={group['sample_ts']!r}, "
                f"pipeline_cycles.id in {ids}. "
                "Resolve manually, then run migrate again."
            )

        if run_max_idx > max_idx_in_group:
            raise ValueError(
                "estimation migration 0006: duplicate live (run_id, sample_ts) "
                "has identical raw payloads, but later cycles exist whose Kalman "
                "state may depend on the duplicate row. "
                f"run_id={group['run_id']}, sample_ts={group['sample_ts']!r}, "
                f"max duplicate cycle_index={max_idx_in_group}, "
                f"run max cycle_index={run_max_idx}, pipeline_cycles.id in {ids}. "
                "Replay/recompute the run from a clean snapshot, or trim later "
                "cycles manually, then run migrate again."
            )

        delete_ids = [row.id for row in rows[1:]]
        if delete_ids:
            PipelineCycle.objects.filter(id__in=delete_ids).delete()


