def normalize_existing_rows(apps, schema_editor):
    """Convert pre-cleanup rows to the live-only vocabulary.

    Evaluation summaries are derived data; deleting them avoids unique collisions
    when old train/validation/test rows collapse into a single online segment.
    They can be recomputed with ``evaluate_online``.
    """
    ExperimentRun = apps.get_model("estimation", "ExperimentRun")
    PipelineCycle = apps.get_model("estimation", "PipelineCycle")
    EvaluationSummary = apps.get_model("estimation", "EvaluationSummary")
    existing_tables = set(schema_editor.connection.introspection.table_names())

    if EvaluationSummary._meta.db_table not in existing_tables:
        schema_editor.create_model(EvaluationSummary)

    ExperimentRun.objects.exclude(run_type="live").update(run_type="live")
    PipelineCycle.objects.exclude(source_type="live").update(source_type="live")
    PipelineCycle.objects.exclude(slice_type="online").update(slice_type="online")
    _delete_duplicate_live_timestamps(PipelineCycle)
    _backfill_live_ingest_keys(PipelineCycle)
    EvaluationSummary.objects.all().delete()


